import { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { fetchAvailability } from '../features/tables/tablesSlice';
import { createReservation } from '../features/reservations/reservationsSlice';
import { joinWaitlist } from '../features/waitlist/waitlistSlice';
import { useNavigate } from 'react-router-dom';

export default function ReservePage() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { available, loading } = useSelector(s => s.tables);
  const [search, setSearch] = useState({ date: '', time: '', guests: 1 });
  const [searched, setSearched] = useState(false);
  const [msg, setMsg] = useState('');

  const handleSearch = async e => {
    e.preventDefault();
    // ensure time is in HH:MM 24-hour format
    const params = { ...search };
    if (params.time && params.time.includes('M')) {
      const d = new Date(`1970-01-01 ${params.time}`);
      params.time = `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
    }
    await dispatch(fetchAvailability(params));
    setSearched(true);
  };

  const handleReserve = async (tableId) => {
    const params = { ...search };
    if (params.time && params.time.includes('M')) {
      const d = new Date(`1970-01-01 ${params.time}`);
      params.time = `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
    }
    const res = await dispatch(createReservation({ ...params, tableId }));
    if (!res.error) { setMsg('Reservation confirmed!'); setTimeout(() => navigate('/my-reservations'), 1500); }
    else setMsg(res.payload);
  };

  const handleWaitlist = async () => {
    const res = await dispatch(joinWaitlist({ date: search.date, guests: search.guests }));
    if (!res.error) setMsg('Added to waitlist!');
    else setMsg(res.payload);
  };

  return (
    <div style={styles.wrap}>
      <h2>Find a Table</h2>
      <form onSubmit={handleSearch} style={styles.form}>
        <input style={styles.input} type="date" value={search.date}
          onChange={e => setSearch({ ...search, date: e.target.value })} required />
        <input style={styles.input} type="time" value={search.time}
          onChange={e => setSearch({ ...search, time: e.target.value })} required />
        <input style={styles.input} type="number" min="1" max="20" placeholder="Guests"
          value={search.guests} onChange={e => setSearch({ ...search, guests: parseInt(e.target.value) })} required />
        <button style={styles.btn} type="submit">Search</button>
      </form>

      {msg && <p style={{ color: msg.includes('!') ? 'green' : 'red', textAlign: 'center' }}>{msg}</p>}

      {searched && (
        <>
          {available.length === 0 ? (
            <div style={{ textAlign: 'center', marginTop: 24 }}>
              <p>No tables available. Join the waitlist?</p>
              <button style={styles.btn} onClick={handleWaitlist}>Join Waitlist</button>
            </div>
          ) : (
            <div style={styles.grid}>
              {available.map(t => (
                <div key={t.id} style={styles.card}>
                  <h3>Table {t.number}</h3>
                  <p>Capacity: {t.capacity}</p>
                  <p>Location: {t.location}</p>
                  <button style={styles.btn} onClick={() => handleReserve(t.id)}>Reserve</button>
                </div>
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}

const styles = {
  wrap:  { maxWidth: 900, margin: '32px auto', padding: '0 16px' },
  form:  { display: 'flex', gap: 12, flexWrap: 'wrap', marginBottom: 24 },
  input: { padding: '10px', border: '1px solid #ddd', borderRadius: '4px', fontSize: '1rem', flex: 1, minWidth: 140 },
  btn:   { padding: '10px 20px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  grid:  { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: 16 },
  card:  { background: '#fff', padding: 20, borderRadius: 8, boxShadow: '0 2px 8px rgba(0,0,0,0.08)', textAlign: 'center' },
};
